external_knowledge:
- 'high scorers' refers to users with significant achievement in the points system;
- 'grand total of points' means a sum exceeding 1000 points;
- 'top scores' indicate the highest total points achieved by each user.

sql:
SELECT users.user_name
FROM users
WHERE users.user_id IN (
    SELECT user_achievements.user_id 
    FROM user_achievements
) 
AND users.user_id NOT IN (
    SELECT user_routes.user_id
    FROM user_routes
);

SELECT user_id, total_points
FROM leaderboard
WHERE rank > 3;

SELECT SUM(points_earned) AS total_points_earned
FROM user_routes
WHERE user_id = 0;

SELECT route_id, card_colors
FROM routes
WHERE card_colors NOT IN (
    SELECT color_name
    FROM card_colors
);

SELECT AVG(points) AS average_points
FROM routes
WHERE difficulty_level = 'Easy';

SELECT DISTINCT r.city_to
FROM routes r
INNER JOIN cities c ON r.city_to = c.city_name;

SELECT difficulty_level, AVG(points) AS average_points, SUM(points) AS total_points
FROM routes
GROUP BY difficulty_level;
